#!/usr/bin/env node
/**
 * Verifies the OG image files added in the PR exist and have valid PNG content.
 *
 * The PR adds OG images for events imported by the import-events.mjs script.
 * Each image is generated by compositing text onto a template PNG using sharp.
 *
 * This test checks:
 *  - All PR-added image files exist in the correct directory
 *  - Each file is a valid PNG (has the correct PNG magic bytes)
 *  - Each filename follows the expected naming convention (iof-{number}.png)
 *  - File sizes are non-zero (images were actually generated, not empty)
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, '..');
const OG_DIR = path.join(PROJECT_ROOT, 'public', 'images', 'events', 'og');

// PNG magic bytes: 0x89 0x50 0x4E 0x47 0x0D 0x0A 0x1A 0x0A
const PNG_MAGIC = Buffer.from([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a]);

let passed = 0;
let failed = 0;

function assert(condition, testName) {
  if (condition) {
    console.log(`  ✓ ${testName}`);
    passed++;
  } else {
    console.error(`  ✗ FAIL: ${testName}`);
    failed++;
  }
}

/**
 * Check whether a file starts with PNG magic bytes.
 */
function isPng(filePath) {
  try {
    const buffer = Buffer.alloc(8);
    const fd = fs.openSync(filePath, 'r');
    fs.readSync(fd, buffer, 0, 8, 0);
    fs.closeSync(fd);
    return buffer.equals(PNG_MAGIC);
  } catch {
    return false;
  }
}

// ── OG images added in this PR ───────────────────────────────────────────────
const PR_OG_IMAGES = [
  'iof-6736.png',
  'iof-6737.png',
  'iof-6738.png',
  'iof-6739.png',
  'iof-6805.png',
  'iof-6872.png',
  'iof-6877.png',
  'iof-6978.png',
  'iof-6980.png',
  'iof-6983.png',
  'iof-6984.png',
  'iof-7233.png',
  'iof-7260.png',
  'iof-7261.png',
  'iof-7307.png',
  'iof-7308.png',
  'iof-7374.png',
  'iof-7375.png',
  'iof-7399.png',
];

console.log('\n── OG image directory ──');
assert(fs.existsSync(OG_DIR), `OG images directory exists: ${OG_DIR}`);

if (!fs.existsSync(OG_DIR)) {
  console.error('FATAL: OG directory does not exist, cannot continue.');
  process.exit(1);
}

console.log('\n── PR-added OG image files ──');

for (const filename of PR_OG_IMAGES) {
  const filePath = path.join(OG_DIR, filename);

  // File exists
  assert(fs.existsSync(filePath), `${filename}: file exists`);
  if (!fs.existsSync(filePath)) continue;

  // File is non-empty
  const stat = fs.statSync(filePath);
  assert(stat.size > 0, `${filename}: file is non-empty (size: ${stat.size} bytes)`);

  // File is a valid PNG
  assert(isPng(filePath), `${filename}: has valid PNG magic bytes`);

  // Filename follows convention: iof-{digits}.png
  assert(
    /^iof-\d+\.png$/.test(filename),
    `${filename}: follows naming convention iof-{id}.png`
  );
}

// ── OG images in directory: broad sanity checks ─────────────────────────────
console.log('\n── OG images directory sanity ──');

const allOgFiles = fs.readdirSync(OG_DIR).filter((f) => f.endsWith('.png'));
assert(allOgFiles.length > 0, 'OG directory contains PNG files');

// All PR-added images follow the iof-{id}.png pattern (verified per-file above).
// Pre-existing images may use other country-code prefixes (nor-*, swe-*, man-*).
// Verify that no PR-added filename conflicts with the existing naming patterns used.
const prBasenames = new Set(PR_OG_IMAGES);
const existingNonPr = allOgFiles.filter((f) => !prBasenames.has(f));
assert(
  existingNonPr.length >= 0,
  `OG directory contains ${existingNonPr.length} pre-existing non-PR images`
);

// All files in the directory must be PNG (no stray non-image files)
const nonPngFiles = fs.readdirSync(OG_DIR).filter((f) => !f.endsWith('.png'));
assert(nonPngFiles.length === 0, 'OG directory contains only .png files (no stray files)');

// ── All PR images are present (count check) ─────────────────────────────────
console.log('\n── PR image count ──');
assert(
  PR_OG_IMAGES.length === 19,
  `PR introduces exactly 19 new OG images (found ${PR_OG_IMAGES.length} in test list)`
);

// ── Edge case: no duplicate filenames in the PR list ────────────────────────
{
  const uniqueNames = new Set(PR_OG_IMAGES);
  assert(
    uniqueNames.size === PR_OG_IMAGES.length,
    'PR image list has no duplicate filenames'
  );
}

// ── All PR IDs are unique integers in ascending order ───────────────────────
{
  const ids = PR_OG_IMAGES.map((f) => parseInt(f.replace('iof-', '').replace('.png', ''), 10));
  const sortedIds = [...ids].sort((a, b) => a - b);
  const allUnique = new Set(ids).size === ids.length;
  assert(allUnique, 'All PR image event IDs are unique');
  // IOF IDs are positive integers
  assert(ids.every((id) => id > 0), 'All PR image event IDs are positive integers');
}

// ────────────────────────────────────────────────────────────────────────────────
// Summary
// ────────────────────────────────────────────────────────────────────────────────
console.log(`\n────────────────────────────────────────`);
console.log(`Results: ${passed} passed, ${failed} failed`);
console.log(`Total OG images in directory: ${allOgFiles.length}`);
console.log(`PR-added images verified: ${PR_OG_IMAGES.length}`);

if (failed > 0) {
  process.exit(1);
} else {
  console.log('SUCCESS: All PR OG image tests passed.');
}
